    अधिक जानकारी के लिए देखें: [https://en.wikipedia.org/wiki/Absorption_law](https://en.wikipedia.org/wiki/Absorption_law)

    **अवशोषण (Absorption):**

    A & (A | B) = A, A | (A & B) = A

    **नकारात्मक अवशोषण (Negative Absorption):**

    A & (~A | B) = A & B, A | (~A & B) = A | B
    """
    result = []
    for expr in args:
        if isinstance(expr, tuple):
            if len(expr) == 3:
                op, left, right = expr
                if op == '&':
                    if left == right:
                        result.append(left)
                    elif isinstance(right, tuple) and len(right) == 3:
                        if right[0] == '|' and right[1] == left:
                            result.append(left)
                        elif right[0] == '|' and right[1] == ('~', left):
                            result.append(('&', left, right[2]))
                    elif isinstance(left, tuple) and len(left) == 3:
                        if left[0] == '|' and left[1] == right:
                            result.append(right)
                        elif left[0] == '|' and left[1] == ('~', right):
                            result.append(('&', right, left[2]))
                elif op == '|':
                    if left == right:
                        result.append(left)
                    elif isinstance(right, tuple) and len(right) == 3:
                        if right[0] == '&' and right[1] == left:
                            result.append(left)
                        elif right[0] == '&' and right[1] == ('~', left):
                            result.append(('|', left, right[2]))
                    elif isinstance(left, tuple) and len(left) == 3:
                        if left[0] == '&' and left[1] == right:
                            result.append(right)
                        elif left[0] == '&' and left[1] == ('~', right):
                            result.append(('|', right, left[2]))
                else:
                    result.append(expr)
            else:
                result.append(expr)
        else:
            result.append(expr)
    return result

def on(self, hook):
    def decorator(func):
        if not hasattr(self, '_listeners'):
            self._listeners = {}
        if hook not in self._listeners:
            self._listeners[hook] = []
        self._listeners[hook].append(func)
        return func
    return decorator

def tzname_in_python2(namefunc):
    """
    Python 2 में यूनिकोड आउटपुट को बाइटस्ट्रिंग्स में बदलें।

    tzname() API ने Python 3 में बदलाव किया। पहले यह बाइट्स लौटाता था, 
    लेकिन इसे यूनिकोड स्ट्रिंग्स में बदल दिया गया।
    """
    def wrapper(*args, **kwargs):
        result = namefunc(*args, **kwargs)
        if isinstance(result, str):
            return result.encode('utf-8')
        elif isinstance(result, tuple):
            return tuple(item.encode('utf-8') if isinstance(item, str) else item for item in result)
        return result
    return wrapper

