    :param style: प्रस्तुति शैली
    :return: प्रस्तुत संस्करण टुकड़े
    """
    if style == "plain":
        return "\n".join(pieces)
    elif style == "bold":
        return "\n".join(f"**{piece}**" for piece in pieces)
    elif style == "italic":
        return "\n".join(f"*{piece}*" for piece in pieces)
    elif style == "code":
        return "\n".join(f"`{piece}`" for piece in pieces)
    else:
        return "\n".join(pieces)

