def merge_extra_vars(vars_dict, extra_vars=None):
    """
    ``vars_dict`` को ``extra-vars`` के साथ मर्ज (जोड़ना) करें।

    :param vars_dict: वह डिक्शनरी जिसमें extra-vars को मर्ज करना है
    :param extra_vars: extra-vars की सूची (लिस्ट)
    """
    if extra_vars is None:
        extra_vars = []

    for var in extra_vars:
        if '=' in var:
            key, value = var.split('=', 1)
            vars_dict[key] = value
        else:
            vars_dict[var] = None

    return vars_dict

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    तर्कों को सही प्रकारों में परिवर्तित करता है और values_dict पैरामीटर को संशोधित करता है।

    डिफ़ॉल्ट रूप से, सभी मान स्ट्रिंग्स के रूप में होते हैं।

    :param parser_name: कमांड का नाम, जैसे main, virsh, ospd, आदि।
    :param values_dict: तर्कों के साथ डिक्शनरी।
    """
    for key, value in values_dict.items():
        if isinstance(value, str):
            # Try to convert to int
            try:
                values_dict[key] = int(value)
                continue
            except ValueError:
                pass

            # Try to convert to float
            try:
                values_dict[key] = float(value)
                continue
            except ValueError:
                pass

            # Try to convert to boolean
            if value.lower() in ('true', 'false'):
                values_dict[key] = value.lower() == 'true'
                continue

            # Try to convert to list if the value is comma-separated
            if ',' in value:
                values_dict[key] = value.split(',')
                continue

import os
import json

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    प्लगइन स्पेसिफिकेशन से एक फ्लैट डिक्शनरी बनाता है।

    :param plugin_dir: प्लगइन की डायरेक्टरी का पथ
    :return: एक फ्लैट डिक्शनरी जो प्लगइन की प्रॉपर्टीज़ को समाहित करती है
    """
    spec_file = os.path.join(plugin_dir, 'plugin_spec.json')
    if not os.path.exists(spec_file):
        raise FileNotFoundError(f"Plugin specification file not found in {plugin_dir}")

    with open(spec_file, 'r') as file:
        spec_data = json.load(file)

    flat_dict = {}
    def flatten(d, parent_key='', sep='.'):
        for k, v in d.items():
            new_key = f"{parent_key}{sep}{k}" if parent_key else k
            if isinstance(v, dict):
                flatten(v, new_key, sep=sep)
            else:
                flat_dict[new_key] = v
        return flat_dict

    return flatten(spec_data)

